const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};
const expectedToken = (typeof process !== 'undefined' ? process.env.N8N_WEBHOOK_TOKEN : '') || '';
const actualToken = headers['x-servicedesk-token'] || headers['X-ServiceDesk-Token'] || headers['X-Servicedesk-Token'] || '';

if (!expectedToken || actualToken !== expectedToken) {
  return [{
    json: {
      statusCode: 401,
      response: {
        error: { code: 'unauthorized', message: 'Токен webhook отсутствует или некорректен.' }
      }
    }
  }];
}

const fullName = String(body.full_name || '').trim();
const employeeId = String(body.employee_id || '').trim();

if (!fullName) {
  return [{
    json: {
      statusCode: 400,
      response: {
        error: { code: 'missing_full_name', message: 'full_name (ФИО) обязателен.' }
      }
    }
  }];
}

const parts = fullName.split(/\s+/);
return [{
  json: {
    statusCode: 200,
    full_name: fullName,
    employee_id: employeeId,
    last_name: parts[0] || '',
    first_name: parts[1] || '',
    middle_name: parts[2] || '',
    hr_api_base_url: process.env.HR_API_BASE_URL || 'https://hr-api.example.com'
  }
}];

const input = $input.first().json;
const positionsData = input.positionsHired || [];
const orgData = input.orgStructure || [];
const lastName = String(input.last_name || '').toLowerCase();
const firstName = String(input.first_name || '').toLowerCase();
const middleName = String(input.middle_name || '').toLowerCase();
const employeeId = String(input.employee_id || '').trim();

const employees = [];
for (const le of positionsData) {
  for (const pos of le.Positions || []) {
    for (const emp of pos.Employees || []) {
      const pi = emp.EmployeeInfo?.PersonInfo || {};
      employees.push({
        employeeGid: emp.EmployeeGID,
        lastName: pi.Last_name || '',
        firstName: pi.First_name || '',
        middleName: pi.Middle_name || '',
        fullName: [pi.Last_name, pi.First_name, pi.Middle_name].filter(Boolean).join(' '),
        positionGid: pos.PositionGID,
        positionName: pos.PositionName,
        orgUnitGid: pos.OrgUnitGID,
        orgUnitName: pos.OrgUnitName,
        legalEntity: le.LegalEntity
      });
    }
  }
}

let candidates = employees.filter(e => {
  const ln = String(e.lastName || '').toLowerCase() === lastName;
  const fn = !firstName || String(e.firstName || '').toLowerCase() === firstName;
  const mn = !middleName || String(e.middleName || '').toLowerCase() === middleName;
  return ln && fn && mn;
});

const managerMap = {};
for (const le of orgData) {
  for (const ou of le.OrgUnits || []) {
    if (ou.ManagerPositionGID) {
      managerMap[ou.OrgUnitGID] = {
        managerPositionGid: ou.ManagerPositionGID,
        orgUnitName: ou.Name
      };
    }
  }
}

const results = [];
for (const cand of candidates) {
  const orgInfo = managerMap[cand.orgUnitGid];
  let manager = null;
  let managerCandidates = [];
  if (orgInfo) {
    managerCandidates = employees.filter(e => e.positionGid === orgInfo.managerPositionGid);
    if (managerCandidates.length === 1) {
      manager = managerCandidates[0]; }
  }
  results.push({
    employeeGid: cand.employeeGid,
    fullName: cand.fullName,
    positionName: cand.positionName,
    orgUnitName: cand.orgUnitName,
    legalEntity: cand.legalEntity,
    managerFullName: manager ? manager.fullName : null,
    managerPositionName: manager ? manager.positionName : null,
    managerCandidates: managerCandidates.map(m => ({
      employeeGid: m.employeeGid,
      fullName: m.fullName,
      positionName: m.positionName
    })),
    ambiguityWarning: managerCandidates.length > 1 ? 'Найдено несколько сотрудников на должности руководителя.' : null
  });
}

return [{
  json: {
    statusCode: 200,
    query: {
      full_name: input.full_name,
      employee_id: employeeId,
      last_name: input.last_name,
      first_name: input.first_name,
      middle_name: input.middle_name
    },
    candidatesFound: candidates.length,
    candidates: results,
    note: employeeId ? 'Фильтрация по табельному номеру требует доработки: EmployeeID отсутствует в /Positions.Hired, доступен только через /Employee.Subordinates.Administrative после получения EmployeeGID.' : null
  }
}];
